class Pet:
    def __init__(self, name):
        self.name = name
        self.hunger = 50

    def feed(self, amount):
        self.hunger -= amount

    def __str__(self):
        return f'Pet {self.name} has hunger level {self.hunger}'

my_pet = Pet('Fluffy')
my_pet.feed(20)
print(my_pet)
